# Sponsor accountability tracking — minimal implementation

from datetime import date, timedelta
from dataclasses import dataclass, field
from typing import Literal

@dataclass
class Blocker:
    id: str
    submitted: date
    description: str
    status: Literal["Open", "Cleared", "Escalated"]
    cleared_date: date | None = None

    @property
    def days_open(self) -> int:
        end = self.cleared_date or date.today()
        return (end - self.submitted).days

    @property
    def breaches_sla(self) -> bool:
        return self.status == "Open" and self.days_open > 5

@dataclass
class SponsorAccountability:
    sponsor_name: str
    program_id: str
    okrs: dict[str, dict]           # {"KR1": {"target": 3, "current": 2}}
    blockers: list[Blocker] = field(default_factory=list)
    esc_sessions_attended: int = 0
    esc_sessions_total: int = 0

    def attendance_rate(self) -> float:
        if self.esc_sessions_total == 0:
            return 1.0
        return self.esc_sessions_attended / self.esc_sessions_total

    def sla_breach_count(self) -> int:
        return sum(1 for b in self.blockers if b.breaches_sla)

    def health_status(self) -> str:
        issues = 0
        if self.attendance_rate() < 0.83:   # < 10/12 sessions
            issues += 1
        if self.sla_breach_count() > 0:
            issues += 1
        okr_miss = sum(
            1 for kr in self.okrs.values()
            if kr["current"] < kr["target"] * 0.7
        )
        if okr_miss >= 2:
            issues += 1
        return "RED" if issues >= 2 else "AMBER" if issues == 1 else "GREEN"
